<?php
namespace app\Services; use app\Repositories\BookRepository; use app\Repositories\InventoryRepository; use app\Requests\Validator;
class BookService{ private BookRepository $repo; public function __construct(){ $this->repo=new BookRepository(); } public function paginate($q='', $page=1,$perPage=10){return $this->repo->paginate($q,(int)$page,(int)$perPage);} public function all(){return $this->repo->all();} public function find($id){return $this->repo->find((int)$id);} public function save(array $d,?int $id=null):array{ $e=Validator::required($d,['isbn'=>'ISBN','title'=>'Tên sách','book_type_id'=>'Loại sách','author'=>'Tác giả','quantity'=>'Số lượng']); $e+=Validator::numberMin($d,'quantity','Số lượng',0); $e+=Validator::numberMin($d,'price','Giá',0); if($e)return ['ok'=>false,'errors'=>$e]; $id?$this->repo->update($id,$d):$id=$this->repo->create($d); return ['ok'=>true,'data'=>$this->repo->find($id)]; } public function delete(int $id):array{ if((new InventoryRepository())->hasBorrowHistory('book',$id))return ['ok'=>false,'message'=>'Không thể xóa sách đã có lịch sử mượn']; $this->repo->delete($id); return ['ok'=>true]; }}
